const html = $input.first().json.body || '';
const url = $input.first().json.url;

// Simple tests only - don't break anything!
const tests = {
  http200: $input.first().json.statusCode === 200,
  hasCanvas: html.includes('id="mathCanvas"'),
  hasRender: html.includes('renderScene') || html.includes('drawVisualization'),
  hasBackLink: html.includes('p1.html') || html.includes('../p1.html')
};

$json.url = url;
$json.tests = tests;
$json.allPassed = Object.values(tests).every(v => v);

return $json;
